sys_script_include.script:
var AN_BRScanner = Class.create();

AN_BRScanner.prototype = {

    scan: function(scanId) {

        var scanGR = new GlideRecord('x_1920012_apprai_0_an_scan');

        if (!scanGR.get(scanId))
            return;

        var scopeName = scanGR.app_scope.toString();

        var issueCount = 0;

        var brGR = new GlideRecord('sys_script');
        brGR.addQuery('sys_scope.scope', scopeName);
        brGR.query();

        while (brGR.next()) {

            if (gs.nil(brGR.condition)) {

                this.createFinding(
                    scanId,
                    'maintainability',
                    'medium',
                    'Missing Condition',
                    'Business Rule "' +
                    brGR.name +
                    '" has no condition.'
                );

                issueCount++;
            }

            var scriptText = brGR.script.toString();

            if (scriptText.length > 1000) {

                this.createFinding(
                    scanId,
                    'maintainability',
                    'high',
                    'Large Business Rule',
                    'Business Rule "' +
                    brGR.name +
                    '" contains a large script.'
                );

                issueCount++;
            }
        }

        var score = Math.max(0, 100 - (issueCount * 10));

        var scorecard = new GlideRecord('x_1920012_apprai_0_an_scorecard');
        scorecard.addQuery('scan', scanId);
        scorecard.query();

        if (scorecard.next()) {
            scorecard.maintainability_score = score;
            scorecard.update();
        }
    },

    createFinding: function(scanId, dimension, severity, title, description) {

        var finding = new GlideRecord('x_1920012_apprai_0_an_finding');

        finding.initialize();
        finding.scan = scanId;
        finding.dimension = dimension;
        finding.severity = severity;
        finding.title = title;
        finding.description = description;
        finding.insert();
    },

    type: 'AN_BRScanner'
};
